questionvariables.text:
/* Parallel sides */
a : rand(6) + 10;
b : rand(5) + 4;

if b >= a then (tmp:a, a:b+2, b:tmp-2);

/* Height */
h : rand(5) + 4;

/* Geometry */
diff : (a - b)/2;
slant : float(sqrt(h^2 + diff^2));

/* Area */
ta1 : (1/2)*(a + b)*h;

/* --- Common mistakes --- */

/* 1. Missing 1/2 factor */
mistake1 : (a + b)*h;

/* 2. Using slanted side instead of height */
mistake2 : (1/2)*(a + b)*slant;

/* 3. Adding all four sides (treating like perimeter idea) */
mistake3 : (1/2)*(a + b + 2*slant)*h;
